import pytest
import torch
import numpy as np
import sys, os
sys.path.insert(0, os.path.join(os.path.dirname(__file__), '..'))

def sharpe_ratio(returns, risk_free=0.0, annualize=252):
    excess = returns - risk_free / annualize
    if excess.std() < 1e-9: return 0.0
    return float(excess.mean() / excess.std() * (annualize ** 0.5))

def sortino_ratio(returns, risk_free=0.0, annualize=252):
    excess = returns - risk_free / annualize
    downside = excess[excess < 0]
    if len(downside) == 0 or downside.std() < 1e-9: return 0.0
    return float(excess.mean() / downside.std() * (annualize ** 0.5))

def max_drawdown(returns):
    cum = (1 + np.array(returns)).cumprod()
    rolling_max = np.maximum.accumulate(cum)
    dd = (cum - rolling_max) / rolling_max
    return float(dd.min())

def calmar_ratio(returns, annualize=252):
    ann_ret = float(np.mean(returns) * annualize)
    mdd = abs(max_drawdown(returns))
    if mdd < 1e-9: return 0.0
    return ann_ret / mdd

def win_rate(returns):
    if len(returns) == 0: return 0.0
    return float(np.sum(np.array(returns) > 0) / len(returns))

def value_at_risk(returns, alpha=0.05):
    return float(np.percentile(returns, alpha * 100))

def cvar(returns, alpha=0.05):
    var = value_at_risk(returns, alpha)
    tail = np.array(returns)[np.array(returns) <= var]
    return float(tail.mean()) if len(tail) > 0 else var

