def test_cvar_leq_var(seed, n, alpha, mu, sigma):
    rng = np.random.default_rng(seed)
    rets = rng.normal(mu, sigma, n)
    var = value_at_risk(rets, alpha)
    cv = cvar(rets, alpha)
    assert cv <= var + 1e-9
